import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../somefile.txt"; // User input containing path traversal

        // Define a base directory for file operations
        String baseDirectory = "data/";

        try {
            // Validate user input to prevent path traversal
            Path resolvedPath = Paths.get(baseDirectory).resolve(userInput).normalize();

            if (!resolvedPath.startsWith(Paths.get(baseDirectory))) {
                throw new SecurityException("Invalid file path specified.");
            }

            File file = resolvedPath.toFile();
            System.out.println("Reading file: " + file.getAbsolutePath());
            byte[] fileContent = Files.readAllBytes(file.toPath());
            System.out.println("File content: " + new String(fileContent));
        } catch (IOException | SecurityException e) {
            e.printStackTrace();
        }
    }
}

